const tests = [];
const timestamp = new Date().toISOString();
try {
  const ledger = await this.helpers.request({ method: 'GET', uri: $vars.N8N_HOST + '/api/v1/data-tables/JofPMjEUNrEu9lao/rows?limit=1', headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY }, json: true, simple: false });
  tests.push({ test: 'ERROR_LEDGER_READ', pass: !!ledger && !ledger.error, details: 'Readable' });
} catch(e) { tests.push({ test: 'ERROR_LEDGER_READ', pass: false, details: e.message }); }
try {
  const fixes = await this.helpers.request({ method: 'GET', uri: $vars.N8N_HOST + '/api/v1/data-tables/nBU0Mfop4Yqb1W7q/rows?limit=1', headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY }, json: true, simple: false });
  tests.push({ test: 'KNOWN_FIXES_READ', pass: !!fixes && !fixes.error, details: 'Readable' });
} catch(e) { tests.push({ test: 'KNOWN_FIXES_READ', pass: false, details: e.message }); }
try {
  const wf = await this.helpers.request({ method: 'GET', uri: $vars.N8N_HOST + '/api/v1/workflows/O7zDlmGScIBCTrEo', headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY }, json: true, simple: false });
  tests.push({ test: 'RESPONDER_ACTIVE', pass: wf && wf.active === true, details: wf.active ? 'Active' : 'INACTIVE' });
} catch(e) { tests.push({ test: 'RESPONDER_ACTIVE', pass: false, details: e.message }); }
try {
  const gwResp = await this.helpers.request({ method: 'POST', uri: $vars.N8N_HOST + '/webhook/orchestrate-v2', headers: { 'Content-Type': 'application/json', 'x-api-key': $vars.key_master }, body: JSON.stringify({ domain: 'handover', action: 'list_workflows', client: 'ascend', params: { limit: 1 } }), json: true, simple: false, timeout: 30000 });
  tests.push({ test: 'GATEWAY_REACHABLE', pass: !gwResp.error, details: gwResp.error ? gwResp.error : 'Reachable' });
} catch(e) { tests.push({ test: 'GATEWAY_REACHABLE', pass: false, details: e.message }); }
return [{ json: { timestamp, tests } }];

const fastTests = $('Fast API Tests').first().json.tests;
const timestamp = $('Fast API Tests').first().json.timestamp;
const canaryNode = $('RESPONDER Canary').first().json;
const fullStr = JSON.stringify(canaryNode);
let canaryPass = false;
let canaryDetail = '';
if (fullStr.includes('RESOLVED')) { canaryPass = true; canaryDetail = 'RESPONDER returned RESOLVED'; }
else if (fullStr.includes('524') || fullStr.includes('timeout') || fullStr.includes('TIMEDOUT') || fullStr.includes('ESOCKETTIMEDOUT')) { canaryPass = true; canaryDetail = 'RESPONDER webhook reachable, processing confirmed (timeout expected)'; }
else if (fullStr.includes('404')) { canaryPass = false; canaryDetail = 'RESPONDER webhook not registered (404)'; }
else if (fullStr.includes('502') || fullStr.includes('503')) { canaryPass = false; canaryDetail = 'n8n instance unreachable: ' + fullStr.substring(0, 150); }
else { canaryPass = !fullStr.includes('ECONNREFUSED'); canaryDetail = 'Response: ' + fullStr.substring(0, 200); }
fastTests.push({ test: 'RESPONDER_WEBHOOK', pass: canaryPass, details: canaryDetail });
const allPass = fastTests.every(t => t.pass);
const failCount = fastTests.filter(t => !t.pass).length;
return [{ json: { timestamp, allPass, failCount, totalTests: fastTests.length, tests: fastTests } }];
